import{_ as t,o as i,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const l="/images/uebung070.jpg",d="/images/uebung071.jpg",b=JSON.parse('{"title":"Übung Lektion 43","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung43.md","filePath":"lektionen/uebung43.md"}'),a={name:"lektionen/uebung43.md"};function s(o,e,u,h,c,p){return i(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-43" tabindex="-1">Übung Lektion 43 <a class="header-anchor" href="#ubung-lektion-43" aria-label="Permalink to &quot;Übung Lektion 43&quot;">​</a></h1><p>A) Bilden Sie die in Zeit, Zahl, Modus u. s. w. entsprechende 2. Person zu folgenden Verbformen:</p><ol><li>आर्हम् । आर्हस्</li><li>कुप्येम । कुप्येत</li><li>ऐच्छन् । । ऐच्छत</li><li>ईक्षेरन् । ईक्षेध्वम्</li><li>कल्पने । कल्पध्वे</li><li>क्रामन्ति । क्रामथ</li><li>क्रेष्याम । क्रेष्यसि</li><li>गच्छेयम् । गच्छेस्</li><li>गायति । गायसि</li><li>चर्यते । चर्यसे</li><li>चेष्यन्ति । चेष्यथ</li><li>जायेय । जयेथास्</li><li>आज्ञापयत् । अज्ञापयस्</li><li>विजयते । विजयसे</li><li>जीव्येत । जीव्व्येथास्</li><li>तुदामः । तुदथ</li><li>अतरन् । अतरत</li><li>त्यजामि । त्यजसि</li><li>दहेयम् । दहेस्</li><li>आदास्ये । आदास्यसे</li><li>दिशति । दिशसि</li><li>अदूष्यम् । अदुष्यस्</li><li>दृश्यामहे । दृश्यध्वे</li><li>नश्येयुः । नश्येत</li><li>आनीयामहि । आनीयध्वम्</li><li>नृत्यामि । नृत्यसि</li><li>पचेत् । पचेस्</li><li>पतिष्यामि । पतिष्यसि</li><li>आपद्यत । आपद्यथास्</li><li>पिबामः । पिबथ</li><li>अपृच्छ्ये । अपृच्छ्यथास्</li><li>बुध्यामहे । बुध्यध्वे</li><li>भजेम । भजेत</li><li>प्राभवन् । प्राभवत</li><li>भरिष्यन्ते । भरिष्यध्वे</li><li>मन्ये । मन्यसे</li><li>मुच्येरन् । मुच्येध्वम्</li><li>अम्रियन्त । अम्रियध्वम्</li><li>यजेत । यजेथास् । यजेत</li><li>युध्येमहि । युध्येध्वम्</li><li>अरक्षन् । अरक्षत</li><li>लप्स्यन्ते । लप्स्यध्वे</li><li>अवदम् । अवदस्</li><li>औह्ये । औह्यथास्</li><li>वसन्ति । वसथ</li><li>अवावर्तत । अवावर्तथास्</li><li>विशामि । विशसि</li><li>शोचामः । शोचथ</li><li>वर्धेत । वर्धेथास्</li><li>सीदामि । सीदसि</li><li>तिष्ठन्ति । तिष्ठथ</li><li>आहरत् । आहरस्</li></ol><p><img src="'+l+'" alt=""><br> Abb.: दिशसि<br> ताज महल / تاج محل<br> [Bildquelle: Listen Up!. -- <a href="http://www.flickr.com/photos/listenup/311358968/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/listenup/311358968/</a>. -- Zugriff am 2009-01-22. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>B) Übersetzen Sie ins Sanskrit:</p><p>1. Warum sitzt ihr während der Lehrer steht?</p><blockquote><p>कस्माद्गुरौ तिष्ठति सीदथ । कस्माद्गुरौ तिष्ठत्याध्वे ॥१॥</p></blockquote><p>2. Bezweifelst du, ob eine gute Tat eine gute Frucht  hat?</p><blockquote><p>किं विकल्पयसि किं सुकर्मणः सुफलमस्तीति ॥२॥</p></blockquote><p>3. Werdet ihr dem Vater den innersten Tempelschrein zeigen?</p><blockquote><p>कच्चित्पितरं गर्भगृहं दर्शयिष्यथ । कच्चित्पित्रे गर्भगृहं देक्ष्यथ ॥३॥</p></blockquote><p>4. Das Preislied welches Dichters hast du gesungen?</p><blockquote><p>कस्य कवेः स्तोत्रमगायः ॥४॥</p></blockquote><p>5. Werdet ihr diese Früchte verkaufen?</p><blockquote><p>एतानि फलानि विक्रेष्यध्वे । तानि ... ॥५॥</p></blockquote><p>6. Was hast du befohlen?</p><blockquote><p>किमाज्ञापयः ॥६॥</p></blockquote><p>7. Wann hast du dich in Benares aufgehalten (वृत्)?</p><blockquote><p>कदा काश्यामवर्तथाः ॥७॥</p></blockquote><p>8. Habt ihr als Opferherren die Götter mit einem Opfer verehrt?</p><blockquote><p>कच्चिद्देवानयजध्वम् । कच्चिद्देवान्यजमाना अयजध्वम् ॥८॥</p></blockquote><p>9. In welcher Stadt wurdest du geboren?</p><blockquote><p>कस्मिन्नगरे ऽजायथाः ॥९॥</p></blockquote><p>10. Wie rettest du dich (überschreitest) vor dem Feind?</p><blockquote><p>कथं शत्रुं तरसि ॥१०॥</p></blockquote><p><img src="'+d+'" alt=""><br> Abb.: कदा काश्यामवर्तथाः<br> [Bildquelle: bartpogoda. -- <a href="http://www.flickr.com/photos/bartpogoda/330322025/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/bartpogoda/330322025/</a>. -- Zugriff am 2009-01-22. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><table tabindex="0"><thead><tr><th>संवादः</th><th>Gespräch</th></tr></thead><tbody><tr><td>सुरेशः : अशोक१ क्व गच्छसीदानीम् ॥</td><td>Sureśa: Aśoka, wohin gehst du gerade?</td></tr><tr><td>अशोकः : आपणे गच्छामि । सत्वरमेव कानिचित्पण्यानि क्रीत्वा निवर्तिष्ये ॥</td><td>Aśoka: Ich gehe auf den Markt. Ich werde schnell ein paar Waren kaufen und dann zurückkehren.</td></tr><tr><td>सुरेशः : किं कश्चिदुत्सवो ऽद्य तव गृहे ॥</td><td>Sureśa: Gibt es heute etwa ein Fest bei dir zuhause?</td></tr><tr><td>अशोकः : आम् । अद्य पितृपादानां२ जन्मदिनोत्सवः ॥</td><td>Aśoka: Ja, heute ist Geburtstag meines verehrten Vaters.</td></tr><tr><td>सुरेशः : किं वयस्तव३ पितृचरणानाम् ॥</td><td>Sureśa: Wie alt ist dein verehrter Vater?</td></tr><tr><td>अशोकः : पञ्चषष्टिसमायुतं४ मम पितुर्वयः । अद्य मम गृहे बहवः संबन्धिनो मित्राणि चागमिष्यन्ति । त्वयाप्यागब्तव्यम् ॥</td><td>Aśoka: Mein Vater ist 65 Jahre alt. Heute werden viele Verwandte und Freunde in mein haus kommen. Auch du musst kommen!</td></tr><tr><td>सुरेशः : भद्र५ कतिवादन५क् आगमिष्यन्ति जनाः ॥</td><td>Sureśa: Mein Lieber, um wieviel Uhr kommen die Leute?</td></tr><tr><td>अशोकः : समयं किं पृच्छसि । षड्वादनं६ यावदागच्छ७॥</td><td>Aśoka: Du fragst nach der der Zeit? Komme bis spätestens sechs Uhr!</td></tr><tr><td>सुरेशः : सार्धषड्वादनं यावदागच्छामि चेत् ॥</td><td>Sureśa: Und wenn ich bis halb sieben komme?</td></tr><tr><td>अशोकः : नैव षड्वादन एव निश्चितरूपेणागन्तव्यं त्वया ॥</td><td>Aśoka: Keinesfalls! Du musst genau um sechs in vorgeschriebener Form kommen.</td></tr><tr><td>सुरेशः : अस्तु८ । तर्हि गच्छ त्वं । नोचेद्विलम्बो भविष्यति ॥</td><td>Sureśa: So sei es! Geh also! Sonst wirst du dich verspäten.</td></tr><tr><td>अशोकः :  (विपण्यां प्रविशति वणिजमुपसृत्य वदति च) अयि वणिग्वर९ कानिचित्पण्यानि क्रेतुमागतो ऽहम् । देहि१० शीघ्रं मय्हम् ॥</td><td>Aśoka: (Tritt in einen Laden, geht zu Händler und sagt:) Hallo, bester aller Händler, ich bin gekommen, um einige Waren zu kaufen. Gib sie mir schnell!</td></tr><tr><td>वणिक्११ : वत्स त्वं किंकिं क्रेतुमिच्छसि । मम विपणौ बहून्युत्तमोत्तमानि पण्यानि सन्ति तानि च स्वल्पमूल्यानि । वद१२ कियत्परिमाणं किं क्रेतुमिच्छसि ॥</td><td>Händler: Liebster, was willst du Kaufen? In meinem Laden sind viele exzellenteste Waren und die sind sehr billig. Sag wieviel du wovon kaufen willst!</td></tr><tr><td>अशोकः :  सेरभारा१३ शर्करा कियता मूल्येन विक्रीयते ॥</td><td>Aśoka: Wieviel kostet ein Seer Zucker?</td></tr><tr><td>वणिक् :  नाधिक्यं मूल्यम् । केवलमष्टाणकेन१४ दास्यामि सेरभारां शर्कराम् ॥</td><td>Händler: Nicht viel! Ich gebe dir das Seer Zucker für nur acht Anna.</td></tr><tr><td>अशोकः :  तर्हि तोलयित्वा शीघ्रं सेरपरिमितां शर्करां देहि१५ ॥</td><td>Aśoka: Dann wiege mir schnell ein Seer Zucker ab und gib es mir!</td></tr><tr><td>वणिक् :  (शर्करां कर्गले संपुटीकृत्य) बाल१६ गृहाण१७ शर्कराम् । देहि च मह्यमाणकाष्टकम्१८ । सत्वरं देहि ॥</td><td>Händler: (wickelt in Papier den Zucker zu einem Paket): Junge, nimm den Zucker! Gib mir 8 Anna! Mach schnell!</td></tr><tr><td>अशोकः : (आदाय हस्ते तस्य भारं चाल्पं विलोक्य) भो वनिक् । नैषा सेरभारा शर्करा दृश्यते । पुनः सम्यक्तोलयित्वा१९ देहि ॥</td><td>Aśoka: (nimmt es in die Hand und merkt, dass es zuwenig wiegt): Du! Händler! Dies scheint kein Seer Zucker zu sein. Wieg es nochmals korrekt ab und gib es mir dann!</td></tr><tr><td>वणिक् : (सहासम्) किमनेन । अकिञ्चिद्करमेतत् । तव भारवहनक्लेशो ऽल्पो भविष्यति ॥</td><td>Händler: (lachend): Was solls?! Das macht doch nichts. Du wirst weniger Mühe haben, die Last zu tragen.</td></tr><tr><td>अशोकः :  (मनसि२० किंचिद्विचार्याणकचतुष्टयं२१ च तस्य पुरत उपस्थाप्य) भो श्रेष्ठिन्गृहाण२२ मूल्यम् । मया हि शीघ्रं गृहं गन्तव्यम् ॥ (इत्युक्त्वा ततः प्रस्थितः)</td><td>Aśoka: (überlegt kurz und legt ihm 4 Anna hin): Herr Kaufmann, nimm den Preis! Ich muss nämlich schnell nachhause gehen. (Nach diesen Worten bricht er auf).</td></tr><tr><td>वणिक् :  रे बालक२३ । एह्येहि२४ शृणु२५ तावत् ।  अल्पमेव मूल्यं दत्त्वा क्व व्रजसि । आणकचतुष्टयमन्यदपि देहि ॥</td><td>Händler: He, Bub! Komm!, komm!, hör mal! Wohin laufst du davon nachdem du mir zuwenig gezahlt hast? Gib mir weitere vier Anna!</td></tr><tr><td>अशोकः : श्रेष्ठिन्२६ । किमनेन । अकिंचित्करमेतत् । नाणकगणनाक्लेशस्ते ऽल्पीयान्भविष्यति२७ ॥ (इत्युक्त्वा ततो जवेन द्रवति)</td><td></td></tr><tr><td>(विपणिस्थो वञ्चको वनिग्न२८ किमपि कर्तुमशक्नोत्केवलं तस्य मनसि२९ पश्चात्ताप एवासीत्)</td><td></td></tr></tbody></table><p>अशोको गृहमागत्य सर्वमपीतिवृत्तमकथयत् । तत्रस्था सर्वे ऽपि बान्धवा मित्राणि च परमानन्दं प्रापुः । इत्थं जन्मोत्सवः सानन्दं समाप्तिं यातः ॥</p><p>| Aśoka: Kaufmann! Was solls?! Das macht doch nichts. Wirst du nicht weniger Mühe haben, die Annas zu zählen?! (spricht&#39;s und rennt eilig davon)</p><p>(Der betrügerische Händler in seinem Laden konnte nichts tun. Er verspürte nur Reue in seinem Herzen).</p><p>Als Aśoka zuhause war erzählte er die ganze Begebenheit. Alle Verwandten und Freunde amüsierten sich sehr. So wurde die Geburtstagsfeier mit Fröhlichkeit ein Erfolg.</p><p>| | (Nach: Saral Sanskrit Shikshak III, S. 4f.) |   |</p>',33)])])}const k=t(a,[["render",s]]);export{b as __pageData,k as default};
